// Minimal service worker for PWA installation support
self.addEventListener('install', (e) => {
  console.log('[Service Worker] Installed');
});

self.addEventListener('fetch', (e) => {
  // Pass-through strategy
  e.respondWith(fetch(e.request));
});

import React, { useState, useEffect } from 'react';
import { Camera, Shirt, Package, Zap, RefreshCw, Download, Image as ImageIcon, Wand2, Edit3, Settings2, Info, MapPin, Smartphone } from 'lucide-react';
import ImageSelector from './components/ImageSelector';
import { AppStatus, GenerationSettings, CompositionResult } from './types';
import { generateFullComposition, cleanImageBackground } from './services/geminiService';

const PRESET_ENVIRONMENTS = ["Studio tối giản", "Đường phố", "Sân vườn", "Căn hộ cao cấp", "Quán Cafe", "Văn phòng"];
const PRESET_POSES = ["Đứng thẳng", "Đang đi", "Ngồi ghế", "Tạo dáng tay", "Nhìn xa xăm"];
const CLOTHING_TYPES = ["Áo", "Váy/Đầm", "Áo khoác", "Quần/Chân váy", "Set đồ"];

const App: React.FC = () => {
  const [modelImage, setModelImage] = useState<string | null>(null);
  const [clothingImage, setClothingImage] = useState<string | null>(null);
  const [productImage, setProductImage] = useState<string | null>(null);
  const [environmentImage, setEnvironmentImage] = useState<string | null>(null);

  const [cleaningStates, setCleaningStates] = useState({ clothing: false, product: false });
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: "3:4",
    pose: PRESET_POSES[0],
    environment: PRESET_ENVIRONMENTS[0],
    clothingStyle: "Hiện đại",
    clothingType: CLOTHING_TYPES[0],
    clothingDetail: ""
  });

  const [currentResults, setCurrentResults] = useState<CompositionResult[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);
  const [history, setHistory] = useState<CompositionResult[]>([]);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    });
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  const handleDownload = (result: CompositionResult) => {
    if (!result || !result.imageUrl) return;
    const link = document.createElement('a');
    link.href = result.imageUrl;
    link.download = `anh-quan-mkt-${result.id}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleClean = async (type: 'clothing' | 'product') => {
    const targetImg = type === 'clothing' ? clothingImage : productImage;
    if (!targetImg) return;

    setCleaningStates(prev => ({ ...prev, [type]: true }));
    try {
      const cleaned = await cleanImageBackground(targetImg, type === 'clothing' ? 'CLOTHING' : 'PRODUCT');
      if (cleaned) {
        if (type === 'clothing') setClothingImage(cleaned);
        else setProductImage(cleaned);
      }
    } catch (e) {
      alert("Xử lý thất bại. Thử lại nhé!");
    } finally {
      setCleaningStates(prev => ({ ...prev, [type]: false }));
    }
  };

  const handleGenerate = async () => {
    if (!modelImage) {
      alert("Vui lòng tải ảnh Người mẫu làm chủ thể!");
      return;
    }

    if (!clothingImage && !productImage && !settings.clothingDetail) {
      alert("Cần tải lên Trang phục hoặc Sản phẩm để AI có dữ liệu sáng tạo!");
      return;
    }

    setStatus(AppStatus.GENERATING);
    setCurrentResults([]);
    setSelectedResultIndex(0);

    try {
      const promises = [0, 1, 2, 3].map(vId => 
        generateFullComposition(modelImage, clothingImage, productImage, environmentImage, settings, vId)
      );

      const urls = await Promise.all(promises);
      const valid = urls.filter(u => u !== null).map((url, i) => ({
        id: `res-${Date.now()}-${i}`,
        imageUrl: url!,
        prompt: `Ghép ${settings.clothingType} & bối cảnh ${settings.environment}`,
        timestamp: Date.now()
      }));

      if (valid.length > 0) {
        setCurrentResults(valid);
        setHistory(prev => [...valid, ...prev].slice(0, 12));
        setStatus(AppStatus.IDLE);
        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
      } else {
        setStatus(AppStatus.ERROR);
      }
    } catch (e) {
      setStatus(AppStatus.ERROR);
    }
  };

  const isGenerateDisabled = status === AppStatus.GENERATING || !modelImage || (!clothingImage && !productImage && !settings.clothingDetail);

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#050505] text-white selection:bg-indigo-500/30">
      {/* Sidebar - Controls */}
      <div className="w-full lg:w-[450px] glass-morphism border-b lg:border-r border-white/5 p-5 lg:p-6 flex flex-col gap-6 lg:h-screen lg:overflow-y-auto lg:sticky lg:top-0 z-20">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-500/20 shadow-lg">
              <Zap className="w-6 h-6 fill-current" />
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tighter text-indigo-400 leading-none">ANH QUÂN MKT</h1>
              <p className="text-[10px] font-bold text-gray-500 uppercase">AI Studio</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {deferredPrompt && (
              <button 
                onClick={handleInstallApp}
                className="lg:hidden p-2 bg-indigo-600 rounded-lg text-white animate-pulse"
                title="Cài đặt ứng dụng"
              >
                <Smartphone className="w-4 h-4" />
              </button>
            )}
            <Settings2 className="w-5 h-5 text-gray-600" />
          </div>
        </div>

        {deferredPrompt && (
          <button 
            onClick={handleInstallApp}
            className="hidden lg:flex w-full bg-indigo-500/10 border border-indigo-500/30 rounded-xl p-3 gap-3 items-center hover:bg-indigo-500/20 transition-all"
          >
            <Smartphone className="w-5 h-5 text-indigo-400" />
            <div className="text-left">
              <p className="text-[10px] font-bold text-white uppercase leading-none">Cài đặt Studio</p>
              <p className="text-[9px] text-indigo-300">Dùng mượt hơn như một ứng dụng điện thoại</p>
            </div>
          </button>
        )}

        <div className="bg-white/5 border border-white/10 rounded-xl p-3 flex gap-3 items-start">
          <Info className="w-4 h-4 text-indigo-400 shrink-0 mt-0.5" />
          <p className="text-[10px] text-gray-400 leading-relaxed">
            <b>Mẹo:</b> Tách nền Trang phục/Sản phẩm trước khi ghép để AI tạo bóng đổ và khớp bối cảnh hoàn hảo nhất.
          </p>
        </div>

        {/* Input Sections - Grid 2x2 */}
        <div className="grid grid-cols-2 gap-3">
          <ImageSelector 
            label="1. Mẫu (Gốc)" 
            image={modelImage} 
            onImageChange={setModelImage} 
            icon={<Camera className="w-4 h-4" />} 
          />
          <ImageSelector 
            label="2. Đồ (Tách nền)" 
            image={clothingImage} 
            onImageChange={setClothingImage} 
            icon={<Shirt className="w-4 h-4" />} 
            isProcessing={cleaningStates.clothing}
            onProcess={() => handleClean('clothing')}
            processLabel="TÁCH"
          />
          <ImageSelector 
            label="3. SP (Tách nền)" 
            image={productImage} 
            onImageChange={setProductImage} 
            icon={<Package className="w-4 h-4" />} 
            isProcessing={cleaningStates.product}
            onProcess={() => handleClean('product')}
            processLabel="TÁCH"
          />
          <ImageSelector 
            label="4. Cảnh (Nền)" 
            image={environmentImage} 
            onImageChange={setEnvironmentImage} 
            icon={<MapPin className="w-4 h-4" />} 
          />
        </div>

        <div className="space-y-5">
          <div>
            <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-3 block">Loại sản phẩm</label>
            <div className="flex flex-wrap gap-2">
              {CLOTHING_TYPES.map(t => (
                <button 
                  key={t}
                  onClick={() => setSettings({...settings, clothingType: t})}
                  className={`text-[10px] px-3 py-2 rounded-xl border transition-all ${settings.clothingType === t ? 'bg-indigo-600 border-indigo-400' : 'bg-white/5 border-white/5 text-gray-500 hover:bg-white/10'}`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-gray-500 uppercase tracking-tight">Tạo dáng AI</label>
              <select className="w-full bg-white/5 border border-white/5 rounded-xl p-3 text-xs outline-none focus:border-indigo-500/50 appearance-none" value={settings.pose} onChange={e => setSettings({...settings, pose: e.target.value})}>
                {PRESET_POSES.map(p => <option key={p} value={p} className="bg-gray-900">{p}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-gray-500 uppercase tracking-tight">Bối cảnh</label>
              <select 
                disabled={!!environmentImage}
                className={`w-full bg-white/5 border border-white/5 rounded-xl p-3 text-xs outline-none appearance-none ${environmentImage ? 'opacity-30 cursor-not-allowed' : 'focus:border-indigo-500/50'}`} 
                value={settings.environment} 
                onChange={e => setSettings({...settings, environment: e.target.value})}
              >
                {PRESET_ENVIRONMENTS.map(e => <option key={e} value={e} className="bg-gray-900">{e}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-bold text-gray-500 uppercase tracking-tight flex items-center gap-2">
              <Edit3 className="w-3 h-3" /> Ghi chú thêm cho AI
            </label>
            <textarea 
              className="w-full bg-white/5 border border-white/5 rounded-xl p-3 text-xs min-h-[80px] outline-none focus:border-indigo-500/50 transition-all" 
              placeholder="Ví dụ: Áo phông trắng oversize, phối thêm kính râm đen..."
              value={settings.clothingDetail}
              onChange={e => setSettings({...settings, clothingDetail: e.target.value})}
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-2 block">Kích thước khung hình</label>
            <div className="grid grid-cols-5 gap-2">
              {["1:1", "3:4", "4:3", "9:16", "16:9"].map(ratio => (
                <button
                  key={ratio}
                  onClick={() => setSettings({...settings, aspectRatio: ratio as any})}
                  className={`text-[10px] font-bold py-3 rounded-xl border transition-all ${settings.aspectRatio === ratio ? 'bg-white text-black border-white' : 'bg-white/5 border-white/5 text-gray-500 hover:border-white/20'}`}
                >
                  {ratio}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Desktop Generate Button */}
        <div className="hidden lg:block mt-auto pt-4">
          <button
            onClick={handleGenerate}
            disabled={isGenerateDisabled}
            className="w-full bg-white text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-95 disabled:bg-gray-800 disabled:text-gray-600 disabled:scale-100 shadow-xl"
          >
            {status === AppStatus.GENERATING ? <RefreshCw className="animate-spin w-5 h-5" /> : <Wand2 className="w-5 h-5" />}
            XUẤT BẢN KẾT QUẢ
          </button>
        </div>
      </div>

      {/* Main Preview Area */}
      <main className="flex-1 p-4 lg:p-12 bg-[#020202] flex flex-col items-center gap-6 lg:gap-8 overflow-y-auto pb-32 lg:pb-12">
        {!currentResults.length && status !== AppStatus.GENERATING ? (
          <div className="flex-1 flex flex-col items-center justify-center text-center py-20 lg:py-0">
            <div className="w-20 lg:w-24 h-20 lg:h-24 bg-white/5 rounded-[2.5rem] flex items-center justify-center mb-8 border border-white/10 shadow-2xl relative">
               <div className="absolute inset-0 bg-indigo-500/20 blur-2xl rounded-full"></div>
               <ImageIcon className="w-8 h-8 lg:w-10 lg:h-10 text-indigo-400 relative z-10" />
            </div>
            <h2 className="text-2xl lg:text-3xl font-black mb-3 tracking-tight">AI Lookbook Studio</h2>
            <p className="text-gray-500 text-sm max-w-[320px] leading-relaxed">
              Ghép người mẫu và sản phẩm chuyên nghiệp chỉ trong vài giây. Tối ưu cho kinh doanh thời trang Online.
            </p>
          </div>
        ) : (
          <div className={`w-full max-w-4xl flex flex-col gap-6 lg:gap-10 transition-all duration-700 ${status === AppStatus.GENERATING ? 'opacity-10 blur-3xl scale-95 pointer-events-none' : 'opacity-100'}`}>
            <div className="relative mx-auto w-full max-w-[500px] group">
              <div className="absolute -inset-4 bg-indigo-500/15 rounded-[3.5rem] blur-3xl opacity-50 group-hover:opacity-100 transition-opacity"></div>
              <div className="relative rounded-[2.5rem] overflow-hidden border border-white/10 shadow-[0_0_80px_rgba(0,0,0,0.8)] bg-black">
                {currentResults[selectedResultIndex] && (
                  <img src={currentResults[selectedResultIndex].imageUrl} className="w-full h-auto" alt="Preview" />
                )}
                <div className="absolute top-4 lg:top-6 right-4 lg:right-6">
                   <button 
                    onClick={() => handleDownload(currentResults[selectedResultIndex])}
                    className="p-4 bg-white text-black rounded-2xl hover:bg-indigo-500 hover:text-white transition-all shadow-2xl active:scale-90"
                   >
                    <Download className="w-5 h-5" />
                   </button>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-4 gap-3 lg:gap-4 max-w-2xl mx-auto w-full px-2">
              {currentResults.map((res, i) => (
                <div 
                  key={res.id}
                  onClick={() => setSelectedResultIndex(i)}
                  className={`aspect-square rounded-2xl overflow-hidden cursor-pointer border-2 transition-all duration-300 ${selectedResultIndex === i ? 'border-indigo-500 scale-105 shadow-[0_0_20px_rgba(99,102,241,0.4)]' : 'border-white/5 opacity-40 hover:opacity-100'}`}
                >
                  <img src={res.imageUrl} className="w-full h-full object-cover" alt="Variation" />
                </div>
              ))}
            </div>
          </div>
        )}

        {status === AppStatus.GENERATING && (
          <div className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-black/95 backdrop-blur-2xl px-6 text-center">
            <div className="relative mb-8">
              <div className="w-28 h-28 border-[8px] border-indigo-500/10 border-t-indigo-500 rounded-full animate-spin"></div>
              <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 text-indigo-500 fill-current drop-shadow-[0_0_10px_rgba(99,102,241,0.8)]" />
            </div>
            <h3 className="text-2xl font-black tracking-tight mb-3 uppercase">Đang kiến tạo...</h3>
            <p className="text-gray-400 text-sm max-w-[300px] leading-relaxed">
              AI đang tính toán ánh sáng, bóng đổ và khớp trang phục theo tư thế của người mẫu.
            </p>
          </div>
        )}

        {history.length > 0 && (
          <div className="w-full max-w-4xl pt-8 lg:pt-12 border-t border-white/10">
            <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-6 px-4">Lịch sử thiết kế</h3>
            <div className="flex gap-4 overflow-x-auto pb-6 scrollbar-hide px-4">
              {history.map(h => (
                <div 
                  key={h.id}
                  onClick={() => { setCurrentResults([h]); setSelectedResultIndex(0); }}
                  className="group relative flex-shrink-0 w-24 lg:w-28"
                >
                  <div className="aspect-[3/4] rounded-2xl overflow-hidden border border-white/10 opacity-60 hover:opacity-100 transition-all cursor-pointer">
                    <img src={h.imageUrl} className="w-full h-full object-cover" alt="History" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Mobile Sticky Action Bar */}
      <div className="lg:hidden fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black via-black/95 to-transparent z-40">
        <button
          onClick={handleGenerate}
          disabled={isGenerateDisabled}
          className="w-full bg-white text-black font-black py-4 rounded-2xl flex items-center justify-center gap-3 shadow-2xl active:scale-95 disabled:bg-gray-800 disabled:text-gray-600 transition-all"
        >
          {status === AppStatus.GENERATING ? <RefreshCw className="animate-spin w-5 h-5" /> : <Wand2 className="w-5 h-5" />}
          XUẤT BẢN KẾT QUẢ
        </button>
      </div>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        @supports (-webkit-touch-callout: none) {
          .h-screen { height: -webkit-fill-available; }
        }
      `}</style>
    </div>
  );
};

export default App;

