import { GoogleGenAI } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const cleanImageBackground = async (imageBase64: string, type: 'CLOTHING' | 'PRODUCT'): Promise<string | null> => {
  const ai = getAIClient();
  const imageData = imageBase64.split(',')[1];

  const prompt = type === 'CLOTHING' 
    ? "Extract the clothing garment only. Remove hangers, mannequins, and backgrounds. Put on pure white background."
    : "Extract the product/object only. Remove any existing background and shadows. Put on pure white background.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: imageData, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    if (response.candidates?.[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Lỗi xử lý ảnh:", error);
    throw error;
  }
};

export const generateFullComposition = async (
  modelImg: string,
  clothingImg: string | null,
  productImg: string | null,
  environmentImg: string | null,
  settings: {
    aspectRatio: string;
    pose: string;
    environment: string;
    clothingStyle: string;
    clothingType: string;
    clothingDetail: string;
  },
  variationId: number
): Promise<string | null> => {
  const ai = getAIClient();

  const parts: any[] = [
    { inlineData: { data: modelImg.split(',')[1], mimeType: 'image/jpeg' } } // ẢNH 1
  ];

  if (clothingImg) {
    parts.push({ inlineData: { data: clothingImg.split(',')[1], mimeType: 'image/jpeg' } }); // ẢNH 2
  } else {
    parts.push({ text: `[TRỐNG: Hãy tự thiết kế đồ ${settings.clothingType} phong cách ${settings.clothingStyle}]` });
  }

  if (productImg) {
    parts.push({ inlineData: { data: productImg.split(',')[1], mimeType: 'image/jpeg' } }); // ẢNH 3
  }

  if (environmentImg) {
    parts.push({ inlineData: { data: environmentImg.split(',')[1], mimeType: 'image/jpeg' } }); // ẢNH 4
  }

  const variationHints = [
    "Commercial studio lighting, high contrast.",
    "Soft natural sunlight, outdoor vibe.",
    "Fashion editorial style, cinematic shadows.",
    "Sharp clean look, product-focused depth of field."
  ];

  const prompt = `
    NHIỆM VỤ: Ghép ảnh quảng cáo chuyên nghiệp đa lớp.

    DỮ LIỆU ĐẦU VÀO:
    1. ẢNH 1 (Người mẫu): Chủ thể chính. Giữ nguyên gương mặt và đặc điểm.
    2. ẢNH 2 (Trang phục): ${clothingImg ? `Mặc bộ đồ này lên người mẫu. Áp dụng phong cách ${settings.clothingStyle}.` : `Tự tạo bộ đồ ${settings.clothingType} phong cách ${settings.clothingStyle} thời thượng.`}
    3. ẢNH 3 (Sản phẩm - Nếu có): Đặt vào cảnh hoặc cho mẫu cầm một cách tự nhiên.
    4. ẢNH 4 (Bối cảnh - Nếu có): ĐÂY LÀ NỀN CỐ ĐỊNH. Hãy đặt toàn bộ composition vào ĐÚNG bối cảnh này.

    YÊU CẦU KỸ THUẬT:
    - TƯ THẾ: Người mẫu tạo dáng ${settings.pose}.
    - BỐI CẢNH: ${environmentImg ? 'SỬ DỤNG ẢNH 4 LÀM NỀN.' : `Tạo bối cảnh: ${settings.environment}.`}
    - CHI TIẾT PHONG CÁCH: ${settings.clothingStyle}. ${settings.clothingDetail}.
    - ÁNH SÁNG: Phải khớp hoàn toàn giữa người mẫu và bối cảnh (đặc biệt nếu dùng ẢNH 4). Tạo bóng đổ đổ xuống sàn/tường của ẢNH 4.
    - PHONG CÁCH: ${variationHints[variationId]}
    - CHẤT LƯỢNG: Photorealistic, 8k, high-end fashion retouch.
  `;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: { imageConfig: { aspectRatio: settings.aspectRatio as any } }
    });

    if (response.candidates?.[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

