import { GoogleGenAI } from "@google/genai";

export const cleanImageBackground = async (imageBase64: string, type: 'CLOTHING' | 'PRODUCT'): Promise<string | null> => {
  // Always create a new instance before making an API call to ensure current API Key is used
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imageData = imageBase64.split(',')[1];

  const prompt = type === 'CLOTHING' 
    ? "Extract the clothing garment only. Remove hangers, mannequins, and backgrounds. Put on pure white background."
    : "Extract the product/object only. Remove any existing background and shadows. Put on pure white background.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: imageData, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    if (response.candidates?.[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Lỗi xử lý ảnh:", error);
    throw error;
  }
};

export const generateFullComposition = async (
  modelImg: string,
  clothingImg: string | null,
  productImg: string | null,
  environmentImg: string | null,
  settings: {
    aspectRatio: string;
    pose: string;
    environment: string;
    clothingStyle: string;
    clothingType: string;
    clothingDetail: string;
    shotType: string;
  },
  variationId: number
): Promise<string | null> => {
  // Always create a new instance to pick up potentially new API Key (from window.aistudio.openSelectKey)
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const parts: any[] = [
    { inlineData: { data: modelImg.split(',')[1], mimeType: 'image/jpeg' } } 
  ];

  if (clothingImg) {
    parts.push({ inlineData: { data: clothingImg.split(',')[1], mimeType: 'image/jpeg' } });
  }

  if (productImg) {
    parts.push({ inlineData: { data: productImg.split(',')[1], mimeType: 'image/jpeg' } });
  }

  if (environmentImg) {
    parts.push({ inlineData: { data: environmentImg.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const lightingStyles = [
    "Golden hour sunlight, long shadows, warm cinematic glow.",
    "Professional high-fashion studio lighting, soft box shadows.",
    "Dramatic street lighting, neon reflections, urban atmosphere.",
    "Soft overcast day, neutral tones, high dynamic range."
  ];

  const prompt = `
    TASK: Professional High-End Fashion Composition.

    SHOT CONFIG:
    - CAMERA ANGLE: ${settings.shotType}
    - MODEL POSE: ${settings.pose}
    - CLOTHING: ${settings.clothingType} in ${settings.clothingStyle} style. ${settings.clothingDetail}
    - ENVIRONMENT: ${environmentImg ? 'Use IMAGE 4 as fixed background.' : settings.environment}

    REALISM REQUIREMENTS (STRICT):
    - NO ROBOTIC LOOK. Focus on human soul and expressive eyes.
    - SKIN TEXTURE: Hyper-realistic skin pores, subtle imperfections, natural skin tones. NO over-smoothing.
    - LIGHTING: ${lightingStyles[variationId]} The model and environment MUST share the exact same light source and shadows.
    - FABRIC: High detail on fabric weave, natural wrinkles, and movement.
    - QUALITY: Photorealistic masterpiece, 8k resolution, cinematic depth of field, high-end commercial photography.
  `;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      // Upgrading to gemini-3-pro-image-preview for high-quality, soul-full results as requested.
      // This model supports 1K, 2K, 4K and generally avoids the "robotic" look.
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: { 
        imageConfig: { 
          aspectRatio: settings.aspectRatio as any,
          imageSize: "1K" 
        } 
      }
    });

    if (response.candidates?.[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

