const CLOTHING_STYLES = ["Hiện đại", "Tối giản", "Cổ điển (Vintage)", "Sang trọng", "Họa tiết", "Streetwear"];
const SHOT_TYPES = ["Toàn thân (Full Body)", "Trung bình (Medium Shot)", "Cận cảnh (Close-up)", "Góc thấp (Low Angle)", "Góc cao (High Angle)"];

const App: React.FC = () => {
  const [modelImage, setModelImage] = useState<string | null>(null);
  const [clothingImage, setClothingImage] = useState<string | null>(null);
  const [productImage, setProductImage] = useState<string | null>(null);
  const [environmentImage, setEnvironmentImage] = useState<string | null>(null);

  const [cleaningStates, setCleaningStates] = useState({ clothing: false, product: false });
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [hasCustomKey, setHasCustomKey] = useState(false);

  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: "3:4",
    pose: PRESET_POSES[0],
    environment: PRESET_ENVIRONMENTS[0],
    clothingStyle: CLOTHING_STYLES[0],
    clothingType: CLOTHING_TYPES[0],
    clothingDetail: "",
    shotType: SHOT_TYPES[0]
  });

  const [currentResults, setCurrentResults] = useState<CompositionResult[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);
  const [history, setHistory] = useState<CompositionResult[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setHasCustomKey(hasKey);
      } catch (e) {
        console.error("Key check error", e);
      }
    };
    checkKey();
  }, []);

  useEffect(() => {
    setIsTransitioning(true);
    const timer = setTimeout(() => setIsTransitioning(false), 400);
    return () => clearTimeout(timer);
  }, [selectedResultIndex, currentResults]);

  const handleOpenKeyDialog = async () => {
    try {
      await (window as any).aistudio.openSelectKey();
      setHasCustomKey(true);
      setErrorMsg(null);
    } catch (e) {
      console.error("Open key dialog error", e);
    }
  };

  const handleDownload = (result: CompositionResult) => {
    if (!result || !result.imageUrl) return;
    const link = document.createElement('a');
    link.href = result.imageUrl;
    link.download = `anh-quan-mkt-${result.id}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleClean = async (type: 'clothing' | 'product') => {
    const targetImg = type === 'clothing' ? clothingImage : productImage;
    if (!targetImg) return;

    setCleaningStates(prev => ({ ...prev, [type]: true }));
    try {
      const cleaned = await cleanImageBackground(targetImg, type === 'clothing' ? 'CLOTHING' : 'PRODUCT');
      if (cleaned) {
        if (type === 'clothing') setClothingImage(cleaned);
        else setProductImage(cleaned);
      }
    } catch (e) {
      alert("Xử lý thất bại. Có thể do hết quota, hãy thử dùng Key riêng.");
    } finally {
      setCleaningStates(prev => ({ ...prev, [type]: false }));
    }
  };

  const handleGenerate = async () => {
    if (!modelImage) {
      alert("Vui lòng tải ảnh Người mẫu làm chủ thể!");
      return;
    }

    setStatus(AppStatus.GENERATING);
    setErrorMsg(null);
    setCurrentResults([]);
    setSelectedResultIndex(0);

    try {
      const promises = [0, 1, 2, 3].map(vId => 
        generateFullComposition(modelImage, clothingImage, productImage, environmentImage, settings, vId)
      );

      const urls = await Promise.all(promises);
      const valid = urls.filter(u => u !== null).map((url, i) => ({
        id: `res-${Date.now()}-${i}`,
        imageUrl: url!,
        prompt: `Ghép ${settings.clothingType} ${settings.clothingStyle}`,
        timestamp: Date.now()
      }));

      if (valid.length > 0) {
        setCurrentResults(valid);
        setHistory(prev => [...valid, ...prev].slice(0, 12));
        setStatus(AppStatus.IDLE);
      } else {
        setStatus(AppStatus.ERROR);
        setErrorMsg("Không thể tạo ảnh. Vui lòng thử lại.");
      }
    } catch (e: any) {
      console.error("Generation Error:", e);
      setStatus(AppStatus.ERROR);
      if (e.message?.includes("429") || e.message?.includes("RESOURCE_EXHAUSTED")) {
        setErrorMsg("Quota cạn kiệt! Vui lòng sử dụng API Key riêng của bạn để tiếp tục.");
      } else {
        setErrorMsg("Có lỗi xảy ra. Hãy kiểm tra kết nối hoặc đổi API Key.");
      }
    }
  };

  const isGenerateDisabled = status === AppStatus.GENERATING || !modelImage;

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#050505] text-white selection:bg-indigo-500/30 overflow-hidden">
      {/* Sidebar */}
      <div className="w-full lg:w-[450px] glass-morphism border-b lg:border-r border-white/5 p-5 lg:p-6 flex flex-col gap-6 lg:h-screen lg:overflow-y-auto lg:sticky lg:top-0 z-20">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-500/30 shadow-lg relative">
              <Zap className="w-6 h-6 fill-current" />
              {hasCustomKey && (
                <div className="absolute -top-1 -right-1 w-3 h-3 bg-green-500 border-2 border-[#050505] rounded-full animate-pulse"></div>
              )}
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tighter text-indigo-400 leading-none">ANH QUÂN MKT</h1>
              <p className="text-[10px] font-bold text-gray-500 uppercase">Pro Studio v2.5</p>
            </div>
          </div>
          <button onClick={handleOpenKeyDialog} className={`p-2 rounded-lg transition-colors ${hasCustomKey ? 'text-green-400 bg-green-400/10' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}>
            <Key className="w-5 h-5" />
          </button>
        </div>

        {/* Quota Exhausted Warning */}
        {status === AppStatus.ERROR && errorMsg?.includes("Quota") && (
          <div className="bg-red-500/10 border border-red-500/30 rounded-2xl p-4 flex flex-col gap-3">
            <div className="flex items-start gap-3">
              <AlertCircle className="w-5 h-5 text-red-400 shrink-0 mt-0.5" />
              <div className="space-y-1">
                <p className="text-xs font-bold text-red-200 uppercase">Hết lượt truy cập miễn phí</p>
                <p className="text-[10px] text-red-300/80 leading-relaxed">
                  Để tiếp tục sáng tạo không giới hạn và nhận chất lượng Pro (Gemini 3), hãy thêm API Key của bạn.
                </p>
              </div>
            </div>
            <button 
              onClick={handleOpenKeyDialog}
              className="w-full bg-red-500 text-white text-[10px] font-black py-2.5 rounded-xl hover:bg-red-600 transition-colors uppercase tracking-widest"
