              Cấu hình API Key (Miễn phí)
            </button>
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[9px] text-center text-red-300/50 hover:underline">Tìm hiểu về Billing & Key</a>
          </div>
